class CRMDeal {
    async status() {
        await this.doc.trigger('updateProbability')
    }
    async updateProbability() {
        let status = await call("frappe.client.get_value", {
            doctype: "CRM Deal Status",
            fieldname: "probability",
            filters: { name: this.doc.status },
        })

        this.doc.probability = status.probability
    }
}

function setupList({ list, call }) {
    if (!list) return;

    call("aionion_custom.aionion_custom.controllers.crm_lead.get_current_user_roles", {})
    .then((roles) => {
        if (!roles) return;

        let shouldFilter = false;
        if (roles.includes("Insurance Renewals Manager")) {
            shouldFilter = true;
        } else if (roles.includes("Insurance Renewals RM")) {
            shouldFilter = true;
        }

        if (shouldFilter) {
            let currentFilters = list.params.filters || {};
            if (typeof currentFilters === 'string') {
                try { currentFilters = JSON.parse(currentFilters); } catch(e) { currentFilters = {}; }
            }

            // Apply the custom_product filter
            currentFilters["custom_product"] = "Insurance Renewals";
            list.params.filters = currentFilters;

            // Reload the list with the new filters
            if (list.reload) list.reload();
            else if (list.fetch) list.fetch();
        }
    });
}

function setupList({ call }) {
  var userHasUSRole = false;
  call("aionion_custom.aionion_custom.controllers.crm_lead.get_current_user_roles", {})
    .then(function(roles) {
      userHasUSRole = (roles || []).some(function(r) {
        return ["US Subscription RM","US Subscription MIS","US Subscription Admin","System Manager","Administrator"].indexOf(r) !== -1;
      });
    });
  return {
    actions: [
      {
        label: "Customers",
        onClick: function() { window.open("/app/customer", "_blank"); }
      },
      {
        label: "Mail Inbox",
        onClick: function() { window.open("/desk/crm-mail-inbox", "_blank"); }
      },
      {
        label: "Reports",
        onClick: function() {
          var existing = document.getElementById("aion-rpt");
          if (existing) { existing.remove(); return; }

          var box = document.createElement("div");
          box.id = "aion-rpt";
          box.style.cssText = "position:fixed;top:60px;right:20px;background:white;border-radius:10px;box-shadow:0 8px 30px rgba(0,0,0,0.15);z-index:9999;min-width:280px;border:1px solid #e2e8f0;padding:16px";

          var title = document.createElement("p");
          title.style.cssText = "margin:0 0 12px;font-weight:600;font-size:14px;color:#1a202c";
          title.textContent = "Aionion Reports";
          box.appendChild(title);

          var links = [
            { text: "CRM Activity Dashboard", url: "/desk/crm-activity-dashboard" },
            { text: "Daily Login Activity", url: "/app/query-report/Daily%20Login%20Activity" },
          ];
          if (userHasUSRole) {
            links.push({ text: "US Lead Generation Report", url: "/app/query-report/US%20Lead%20Generation%20Report" });
            links.push({ text: "US CRM Details Report", url: "/desk/query-report/US%20CRM%20Details%20Report" });
          }

          links.forEach(function(lnk) {
            var a = document.createElement("a");
            a.href = lnk.url;
            a.target = "_blank";
            a.textContent = lnk.text;
            a.style.cssText = "display:block;padding:8px 10px;margin:4px 0;background:#f0f4ff;border-radius:6px;color:#4361ee;text-decoration:none;font-size:13px";
            box.appendChild(a);
          });

          var closeBtn = document.createElement("button");
          closeBtn.textContent = "Close";
          closeBtn.style.cssText = "margin-top:12px;padding:6px 14px;background:#e2e8f0;border:none;border-radius:6px;cursor:pointer;font-size:12px;width:100%";
          closeBtn.onclick = function() { box.remove(); };
          box.appendChild(closeBtn);

          document.body.appendChild(box);
          setTimeout(function() {
            document.addEventListener("click", function h(e) {
              if (!box.contains(e.target)) { box.remove(); document.removeEventListener("click", h); }
            });
          }, 100);
        }
      }
    ]
  };
}

function _getDidType() {
	try {
		let roles = frappe.boot && frappe.boot.user && frappe.boot.user.roles ? frappe.boot.user.roles : [];
		return (roles.includes("Insurance Renewals RM") || roles.includes("Insurance Renewals Manager")) ? "service" : "sales";
	} catch(e) {}
	return "sales";
}

function setupForm({ doc, call, toast, $dialog }) {
	checkForActiveCalls("CRM Lead", doc.name, call, toast);

	call("aionion_custom.aionion_custom.controllers.crm_lead.get_current_user_roles", {})
	.then(function(roles) {
		var managerRoles = ["Insurance Sales Manager","Insurance Renewals Manager",
			"US Subscription Admin","Capital Manager","Global RM Manager","System Manager","Administrator"];
		var isManager = roles.some(function(r) { return managerRoles.indexOf(r) !== -1; });
		if (isManager) { document.body.classList.add("aion-manager"); }
		else { document.body.classList.remove("aion-manager"); }
	});

	const FIELD_CLASS_MAP = {
		"Parent Policy": "aion-f-parent-policy", "Parent Policy Expiry Date": "aion-f-parent-expiry",
		"Insurance Company (Renewal)": "aion-f-renewal-company", "Source Lead": "aion-f-source-lead",
		"Renewal Due Date": "aion-f-renewal-due", "Status": "aion-f-status", "Remarks": "aion-f-remarks",
		"Upsell": "aion-f-upsell", "Upsell Remarks": "aion-f-upsell-remarks",
		"Sum Insured Current Year": "aion-f-sum-insured-cy", "Updated Insurance Company Name": "aion-f-updated-ins-co",
		"Plan Name": "aion-f-plan-name", "Updated Policy Number": "aion-f-updated-pol-no",
		"Updated Sum Insured": "aion-f-updated-sum", "Payment Mode": "aion-f-payment-mode",
		"Occupation": "aion-f-occupation", "ITR Filed": "aion-f-itr", "Annual Income": "aion-f-annual-income",
		"Education Qualification": "aion-f-education", "Smoker Status": "aion-f-smoker",
		"Height": "aion-f-height", "Weight (kg)": "aion-f-weight", "Vehicle Year": "aion-f-vehicle-year",
		"Vehicle Type": "aion-f-vehicle-type", "Policy Copy / RC Book": "aion-f-policy-copy",
		"Vehicle Number": "aion-f-vehicle-no", "Vehicle Make and Model": "aion-f-vehicle-make",
		"Country of Travel": "aion-f-travel-country", "Duration of Travel (days)": "aion-f-travel-duration",
		"Coverage Amount (USD)": "aion-f-travel-coverage", "Health Type": "aion-f-health-type",
		"Pre-Existing Disease (PED)": "aion-f-ped", "PED Description": "aion-f-ped-desc",
	}
	const RENEWAL_FIELDS = ["aion-f-parent-policy","aion-f-parent-expiry","aion-f-renewal-company","aion-f-source-lead","aion-f-renewal-due","aion-f-status","aion-f-remarks","aion-f-upsell","aion-f-upsell-remarks","aion-f-sum-insured-cy","aion-f-updated-ins-co","aion-f-plan-name","aion-f-updated-pol-no","aion-f-updated-sum"]
	const TERM_FIELDS = ["aion-f-payment-mode","aion-f-occupation","aion-f-itr","aion-f-annual-income","aion-f-education","aion-f-smoker","aion-f-height","aion-f-weight"]
	const MOTOR_FIELDS = ["aion-f-vehicle-year","aion-f-vehicle-type","aion-f-policy-copy","aion-f-vehicle-no","aion-f-vehicle-make"]
	const TRAVEL_FIELDS = ["aion-f-travel-country","aion-f-travel-duration","aion-f-travel-coverage"]
	const HEALTH_FIELDS = ["aion-f-health-type","aion-f-ped","aion-f-ped-desc"]

	const tagFields = () => {
		const walk = (node) => {
			if (node.nodeType === 3) {
				const t = node.textContent.trim()
				const cls = FIELD_CLASS_MAP[t]
				if (cls) { const field = node.parentElement?.closest(".field"); if (field && !field.classList.contains(cls)) field.classList.add(cls) }
			}
			node.childNodes.forEach(walk)
		}
		walk(document.body)
	}
	const updateCSS = () => {
		const entity = doc.custom_entity, product = doc.custom_product, insType = doc.custom_insurance_type
		const isIns = entity === "Aionion Insurance", isRenewal = product === "Insurance Renewals"
		let style = document.getElementById("aion-vis")
		if (!style) { style = document.createElement("style"); style.id = "aion-vis"; document.head.appendChild(style) }
		const hide = (classes) => classes.map(c => "." + c + "{display:none!important}").join("")
		let css = ""
		if (!isIns) { css += hide([...RENEWAL_FIELDS,...TERM_FIELDS,...MOTOR_FIELDS,...TRAVEL_FIELDS,...HEALTH_FIELDS]) }
		else if (isRenewal) {
			if (insType !== "Health") css += hide(HEALTH_FIELDS)
			if (insType !== "Term")   css += hide(TERM_FIELDS)
			if (insType !== "Motor")  css += hide(MOTOR_FIELDS)
			if (insType !== "Travel") css += hide(TRAVEL_FIELDS)
		} else {
			css += hide(RENEWAL_FIELDS)
			if (insType !== "Health") css += hide(HEALTH_FIELDS)
			if (insType !== "Term")   css += hide(TERM_FIELDS)
			if (insType !== "Motor")  css += hide(MOTOR_FIELDS)
			if (insType !== "Travel") css += hide(TRAVEL_FIELDS)
		}
		style.textContent = css
	}
	const applyVisibility = () => { tagFields(); updateCSS() }
	setTimeout(applyVisibility, 200); setTimeout(applyVisibility, 600)
	setTimeout(applyVisibility, 1200); setTimeout(applyVisibility, 2500)
	if (window._aion_iv) clearInterval(window._aion_iv)
	window._aion_iv = setInterval(applyVisibility, 1000)
	setTimeout(() => clearInterval(window._aion_iv), 20000)

	const actions = []

	// ── MAKE A CALL ──────────────────────────────────────────────────────────────
	actions.push({
		label: "Make a call",
		onClick: () => {
			let defaultNumber = doc.mobile_no || doc.phone || "";
			$dialog({
				title: "Make a call",
				html: '<div style="margin-top:8px"><label class="text-sm text-ink-gray-5" style="display:block;margin-bottom:4px">Destination Number</label><input id="smartflo-dest" type="text" value="' + defaultNumber + '" class="form-input" style="width:100%;padding:8px;border:1px solid var(--gray-300);border-radius:8px;font-size:14px" /></div>',
				actions: [{
					label: "Call", variant: "solid",
					onClick: (context) => {
						let num = document.getElementById("smartflo-dest").value;
						if (!num) { toast.error("Please enter a destination number"); return; }
						call("tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.click_to_call",
							{ destination_number: num, did_type: _getDidType() }
						).then((r) => { context.close(); showCallWidget(num, r, null, "CRM Lead", doc.name, call, toast); });
					},
				}],
			});
		},
	});

	// ── SEND EMAIL ───────────────────────────────────────────────────────────────
	actions.push({
		label: "Send Email",
		onClick: () => {
			let defaultEmail = doc.email || doc.lead_email || doc.custom_email || "";
			let leadName = doc.lead_name || doc.name;
			let safeEmail = (defaultEmail || "").replace(/"/g, "&quot;").replace(/</g, "&lt;");
			let safeName = (leadName || "").replace(/"/g, "&quot;").replace(/</g, "&lt;");
			let emailHtml = '<div style="margin-top:8px;display:flex;flex-direction:column;gap:12px;min-width:700px;">'
				+ '<div style="display:flex;gap:12px;">'
				+ '<div style="flex:1;"><label style="font-size:12px;color:#6b7280;display:block;margin-bottom:4px;">To *</label><input id="ae-to" type="text" value="' + safeEmail + '" style="width:100%;padding:9px 12px;border:1px solid #d1d5db;border-radius:8px;font-size:14px;box-sizing:border-box;" /></div>'
				+ '<div style="flex:1;"><label style="font-size:12px;color:#6b7280;display:block;margin-bottom:4px;">CC</label><input id="ae-cc" type="text" placeholder="cc@email.com" style="width:100%;padding:9px 12px;border:1px solid #d1d5db;border-radius:8px;font-size:14px;box-sizing:border-box;" /></div>'
				+ '</div>'
				+ '<div><label style="font-size:12px;color:#6b7280;display:block;margin-bottom:4px;">Subject *</label><input id="ae-subject" type="text" value="Re: ' + safeName + '" style="width:100%;padding:9px 12px;border:1px solid #d1d5db;border-radius:8px;font-size:14px;box-sizing:border-box;" /></div>'
				+ '<div><label style="font-size:12px;color:#6b7280;display:block;margin-bottom:6px;">Message * <span style="font-size:11px;color:#9ca3af;">— type normally, paste Excel table and it appears as a table automatically</span></label>'
				+ '<div id="ae-toolbar" style="display:flex;align-items:center;gap:2px;padding:6px 8px;border:1px solid #d1d5db;border-bottom:none;border-radius:8px 8px 0 0;background:#fafafa;flex-wrap:wrap;">'
				+ '<select id="ae-font" style="border:none;background:transparent;font-size:12px;color:#374151;cursor:pointer;padding:2px 4px;border-radius:4px;height:26px;"><option value="Arial">Arial</option><option value="Georgia">Georgia</option><option value="Times New Roman">Times New Roman</option><option value="Courier New">Courier New</option><option value="Verdana">Verdana</option><option value="Tahoma">Tahoma</option></select>'
