function setupList({ list, call }) {
    if (!list) return;

    call("aionion_custom.aionion_custom.controllers.crm_lead.get_my_team_employees", {})
    .then((employees) => {
        if (!employees || employees.length === 0) return;
        call("aionion_custom.aionion_custom.controllers.crm_lead.get_user_ids_for_employees",
            { employee_names: employees }
        ).then((userIds) => {
            if (!userIds || userIds.length === 0) return;

            // Frappe UI list resource filtering
            let currentFilters = list.params.filters || {};
            if (typeof currentFilters === 'string') {
                try { currentFilters = JSON.parse(currentFilters); } catch(e) { currentFilters = {}; }
            }

            // Apply the lead_owner filter
            currentFilters["lead_owner"] = ["in", userIds];
            list.params.filters = currentFilters;

            // Reload the list with the new filters
            if (list.reload) list.reload();
            else if (list.fetch) list.fetch();
        });
    });
}

function setupForm({ doc, call, toast, $dialog }) {
	// Check for any active calls on page load — resume widget if agent is on a call
	checkForActiveCalls("Customer", doc.name, call, toast);

	return {
		actions: [
			{
				label: "Make a call",
				onClick: () => {
					// Customer doctype uses mobile_no as the primary phone field
					let defaultNumber = doc.mobile_no || doc.phone || "";
					$dialog({
						title: "Make a call",
						html:
							'<div style="margin-top:8px"><label class="text-sm text-ink-gray-5" style="display:block;margin-bottom:4px">Destination Number</label><input id="smartflo-dest" type="text" value="' +
							defaultNumber +
							'" class="form-input" style="width:100%;padding:8px;border:1px solid var(--gray-300);border-radius:8px;font-size:14px" /></div>',
						actions: [
							{
								label: "Call",
								variant: "solid",
								onClick: (context) => {
									let num = document.getElementById("smartflo-dest").value;
									if (!num) {
										toast.error("Please enter a destination number");
										return;
									}
									// did_type "service" → Smartflo uses service_did from Tata Tele Settings
									call(
										"tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.click_to_call",
										{ destination_number: num, did_type: "service" }
									).then((r) => {
										context.close();
										showCallWidget(num, r, null, "Customer", doc.name, call, toast);
									});
								},
							},
						],
					});
				},
			},
		],
	};
}

// ── Poll for incoming calls on form view ─────────────────────────
function checkForActiveCalls(referenceDoctype, referenceDocname, call, toast) {
	let _shownCallIds = new Set();

	function poll() {
		// Don't poll if widget is already showing
		if (document.getElementById("smartflo-call-widget")) return;

		call(
			"tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.get_live_calls",
			{}
		)
			.then((r) => {
				if (!r || !r.agent_number) return;
				let liveCalls = Array.isArray(r.data) ? r.data : [];

				for (let c of liveCalls) {
					let cid = c.call_id;
					if (!cid || _shownCallIds.has(cid)) continue;

					_shownCallIds.add(cid);
					let callerNumber = c.customer_number || c.source || "";
					showCallWidget(callerNumber, null, c, referenceDoctype, referenceDocname, call, toast);
					break;
				}
			})
			.catch(() => {});
	}

	setInterval(poll, 2500);
	poll();
}

